B.Pn=new A.f4("Add Two Numbers","Adds B and C registers, stores result in A","; Add two values using registers B and C\nORG 2000H\n\nMVI B, 14H\nMVI C, 28H\nMOV A, B\nADD C\nSTA 2100H\nHLT\n")
B.Ps=new A.f4("Factorial (5!)","Calculate factorial of 5","; Compute 5! and store the result at 2100H\nORG 2000H\n\nMVI B, 05H      ; B = n\nMVI A, 01H      ; A = running result\nFACT_LOOP: MOV C, B\nCALL MUL_A_BY_C ; A = A * B\nDCR B\nMOV E, A\nMOV A, B\nCPI 01H\nMOV A, E\nJNZ FACT_LOOP\nSTA 2100H\nHLT\n\nMUL_A_BY_C: MOV D, A\nMVI A, 00H\nMUL_LOOP: ADD D\nDCR C\nJNZ MUL_LOOP\nRET\n")
B.Pk=new A.f4("Clear Memory Block","Clears 16 bytes starting at 2100H","; Fill 2100H..210FH with 00H\nORG 2000H\n\nLXI H, 2100H\nMVI B, 10H\nCLEAR_LOOP: MVI M, 00H\nINX H\nDCR B\nJNZ CLEAR_LOOP\nHLT\n")
B.Pl=new A.f4("Rotate Register A","Rotates A register left 4 times","; Rotate A to the left four times\nORG 2000H\n\nMVI A, 96H\nMVI B, 04H\nROT_LOOP: RLC\nDCR B\nJNZ ROT_LOOP\nHLT\n")
B.Pq=new A.f4("Compare and Jump","Compares A with B, jumps based on result","; Compare A and B and set C as relation code\n; 01H = A>B, 02H = A<B, 03H = A==B\nORG 2000H\n\nMVI A, 2AH\nMVI B, 30H\nCMP B\nJC LESS_THAN\nJZ EQUAL_TO\nMVI C, 01H\nJMP DONE\nLESS_THAN: MVI C, 02H\nJMP DONE\nEQUAL_TO: MVI C, 03H\nDONE: HLT\n")
B.Pp=new A.f4("Stack Operations","Demonstrates PUSH and POP","; Push BC onto stack, then pop into DE\nORG 2000H\n\nLXI SP, 2400H\nMVI B, 12H\nMVI C, 34H\nPUSH B\nMVI B, 00H\nMVI C, 00H\nPOP D\nHLT\n")
B.Pr=new A.f4("Copy Memory Block","Copies 8 bytes from 2100H to 2110H","; Copy bytes from source block (HL) to destination (DE)\nORG 2000H\n\nLXI H, 2100H\nLXI D, 2110H\nMVI B, 08H\nCOPY_LOOP: MOV A, M\nSTAX D\nINX H\nINX D\nDCR B\nJNZ COPY_LOOP\nHLT\n")
B.Pj=new A.f4("Binary to BCD","Converts binary to BCD format","; Convert value in A to decimal digits by repeated subtraction\n; Stores hundreds at 2200H, tens at 2201H, ones at 2202H\nORG 2000H\n\nMVI A, 99H\nMVI B, 00H\nMVI C, 00H\nHUND_LOOP: CPI 64H\nJC TENS_LOOP\nSUI 64H\nINR B\nJMP HUND_LOOP\nTENS_LOOP: CPI 0AH\nJC BCD_DONE\nSUI 0AH\nINR C\nJMP TENS_LOOP\nBCD_DONE: STA 2202H\nMOV A, C\nSTA 2201H\nMOV A, B\nSTA 2200H\nHLT\n")
B.Pm=new A.f4("Call Subroutine","Demonstrates CALL and RET","; Call a subroutine that adds B into A\nORG 2000H\n\nMVI A, 15H\nMVI B, 27H\nCALL ADD_SUB\nSTA 2300H\nHLT\n\nADD_SUB: ADD B\nRET\n")
